#include "controller.h"

#include <stdbool.h>
#include <stdint.h>
#include <string.h>

#define CONTROLLER_TEMP_LOW_THRESHOLD 47
#define CONTROLLER_TEMP_HIGH_THRESHOLD 52
#define CONTROLLER_TEMP_EARLY_OFF_THRESHOLD 50
#define CONTROLLER_SENSOR_TIMEOUT_MS 1000U

static void controller_set_safe_off(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_OFF;
}

void controller_init(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller_set_safe_off(controller);
    controller->has_valid_sensor = false;
    controller->last_temperature_c = 0;
    controller->last_valid_sensor_ms = 0U;
}

static bool temperature_is_rising(const controller_t *controller, int new_temp)
{
    if (controller == NULL || !controller->has_valid_sensor) {
        return false;
    }
    return new_temp > controller->last_temperature_c;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };

    if (controller == NULL) {
        return output;
    }

    bool previous_heater_on = controller->heater_on;
    controller_state_t previous_state = controller->state;

    /* Check for sensor timeout first - stale data for more than 1000ms */
    if (input.kind == CONTROLLER_INPUT_NONE && controller->has_valid_sensor) {
        uint32_t now_ms = input.now_ms;
        uint32_t elapsed_ms = now_ms - controller->last_valid_sensor_ms;
        if (elapsed_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
            controller_set_safe_off(controller);
            output.timed_out = true;
            goto return_output;
        }
    }

    switch (input.kind) {
    case CONTROLLER_INPUT_TEMPERATURE:
        controller->has_valid_sensor = true;
        controller->last_temperature_c = input.temperature_c;
        controller->last_valid_sensor_ms = input.now_ms;

        /* Control policy based on temperature */
        if (controller->last_temperature_c < CONTROLLER_TEMP_LOW_THRESHOLD) {
            /* Low temperature: turn heater ON, enter HEATING state */
            controller->heater_on = true;
            controller->state = CONTROLLER_STATE_HEATING;
        } else if (controller->last_temperature_c > CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* Above upper band: turn heater OFF, stay in SAFE_OFF */
            controller_set_safe_off(controller);
        } else if (controller->last_temperature_c >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD &&
                   controller->last_temperature_c <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* In upper band [50, 52]: check if temperature is rising */
            bool temp_rising = temperature_is_rising(controller, controller->last_temperature_c);

            if (temp_rising) {
                /* Temperature rising: turn heater OFF early, but state is HOLDING */
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_HOLDING;
            } else {
                /* Not rising: hold previous safe actuator state */
                controller->state = CONTROLLER_STATE_HOLDING;
            }
        } else {
            /* In lower band [47, 49]: hold previous safe actuator state */
            controller->state = CONTROLLER_STATE_HOLDING;
        }
        break;

    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        /* Explicit sensor timeout: fail safe to heater OFF */
        controller_set_safe_off(controller);
        break;

    case CONTROLLER_INPUT_INVALID_TEMPERATURE:
        /* Malformed input: fail safe to heater OFF */
        controller_set_safe_off(controller);
        break;

    case CONTROLLER_INPUT_NONE:
    default:
        /* No new input - check for timeout on existing valid sensor data */
        if (controller->has_valid_sensor) {
            uint32_t now_ms = input.now_ms;
            uint32_t elapsed_ms = now_ms - controller->last_valid_sensor_ms;
            if (elapsed_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
                controller_set_safe_off(controller);
                output.timed_out = true;
            }
        }
        break;
    }

return_output:
    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_OFF:
    default:
        return "STATE SAFE_OFF";
    }
}

